#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Contraptions;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.ignitable)]
    public class IgnitableBehaviour : AIEntityBehaviour
    {
        public IgnitableBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            SetExplosionTimer(entity, new FrameTimer(30));
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (IsIgnited(entity))
            {
                IgnitedUpdate(entity);
            }
        }
        private void IgnitedUpdate(Entity entity)
        {
            var timer = GetExplosionTimer(entity);
            if (timer == null)
                return;
            timer.Run(entity.GetAttackSpeed());

            if (timer.Frame < 5)
            {
                entity.SetDisplayScale(Vector3.one * Mathf.Lerp(2, 1, timer.Frame / 5f));
            }
            if (timer.Expired)
            {
                var range = entity.GetRange();
                var damage = entity.GetDamage();
                entity.BehaviourExplode(range, damage);
                entity.Remove();
            }
        }
        public static void Ignite(Entity entity)
        {
            SetIgnited(entity, true);
            entity.PlaySound(VanillaSoundID.fuse);
            entity.AddBuff<TNTIgnitedBuff>();
        }
        public static bool IsIgnited(Entity entity) => entity.GetProperty<bool>(PROP_IGNITED);
        public static void SetIgnited(Entity entity, bool value) => entity.SetProperty(PROP_IGNITED, value);
        public static FrameTimer? GetExplosionTimer(Entity entity) => entity.GetProperty<FrameTimer>(PROP_EXPLOSION_TIMER);
        public static void SetExplosionTimer(Entity entity, FrameTimer timer) => entity.SetProperty(PROP_EXPLOSION_TIMER, timer);
        public static readonly VanillaEntityPropertyMeta<bool> PROP_IGNITED = new VanillaEntityPropertyMeta<bool>("ignited");
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_EXPLOSION_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("explosion_timer");
    }
}
